The error "Non-JSON API Error at [404]: 404 File not found" indicates that your frontend received a 404 Not Found response from the backend, but the response's `Content-Type` header was not `application/json` as expected by your `services/api.ts` module.

The backend's `server.js` previously had a catch-all for `/api` routes that intended to return JSON for 404s:
```javascript
app.use('/api', (req, res) => {
    res.status(404).json({ success: false, message: `API endpoint not found: ${req.originalUrl}` });
});
```
While `res.json()` should automatically set the `Content-Type` to `application/json`, the placement of this middleware might have allowed other middleware or an unexpected Express behavior to interfere, resulting in a non-JSON 404.

To fix this, I've moved the API 404 handler *inside* the `apiRouter` itself, making it the very last route/middleware defined within `apiRouter`. This ensures that any request reaching the `/api` prefix that is not handled by a specific API endpoint will be caught by this handler, guaranteeing a JSON 404 response.

// --- START OF FILE server.js ---
// To run this server:
// 1. Ensure Node.js is installed
// 2. Run: npm install express mongoose cors body-parser axios
// 3. Ensure you have built your Vite frontend: navigate to your frontend directory (if separate) and run `npm run build` or `yarn build`. This will create a `dist` folder.
//    IMPORTANT: Make sure the resulting `dist` folder is directly alongside your `server.js` file.
// 4. Run: node server.js (from the root directory where server.js and the 'dist' folder are located)

import express from 'express';
import mongoose from 'mongoose';
import cors from 'cors';
import bodyParser from 'body-parser';
import axios from 'axios';
import path from 'path';
import { fileURLToPath } from 'url';

const app = express();
const PORT = 3000;

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// --- Database Configuration ---
const MONGO_URI = "mongodb+srv://joaquinscarrizo02_db_user:TFFUE8OLVOUdpsow@dbbrief.ul4p4gp.mongodb.net/?retryWrites=true&w=majority&appName=DBBrief";

mongoose.connect(MONGO_URI)
  .then(async () => {
    console.log('✅ MongoDB Connected successfully');
    await seedInitialFeeds();
  })
  .catch(err => console.error('❌ MongoDB Connection Error:', err));

// Middleware
app.use(cors());
app.use(bodyParser.json());

// =============================================================================
// SERVIR ARCHIVOS ESTÁTICOS DEL FRONTEND
// =============================================================================
// Define la ruta a la carpeta 'dist' de tu frontend.
// Esta configuración asume que la carpeta 'dist' está en la misma ubicación que 'server.js'.
const FE_DIST_PATH = path.join(__dirname, 'dist'); // LA RUTA 'dist' YA ESTÁ CORRECTA

console.log(`ℹ️  Sirviendo archivos estáticos del frontend desde: ${FE_DIST_PATH}`);

// Middleware para servir los archivos estáticos
app.use(express.static(FE_DIST_PATH));

// =============================================================================
// DEFINICIÓN DE SCHEMAS Y MODELOS
// =============================================================================

const toJSONConfig = {
  virtuals: true,
  versionKey: false,
  transform: function (doc, ret) {
    delete ret._id;
  }
};

const incidenteSchema = new mongoose.Schema({ fecha: { type: Date, required: true }, tipo: String, entidad: String, pais: String, sector: String, descripcion: String, datosComprometidos: String, actor: String, url: String }, { timestamps: true });
incidenteSchema.set('toJSON', toJSONConfig);

const exploitSchema = new mongoose.Schema({ fecha: { type: Date, required: true }, nombre: String, tipo: String, plataforma: String, cve: String, url: String }, { timestamps: true });
exploitSchema.set('toJSON', toJSONConfig);

const zeroDaySchema = new mongoose.Schema({ idZD: String, fecha: { type: Date, required: true }, nombre: String, plataforma: String, cvss: Number, estado: String, url: String, descripcion: String }, { timestamps: true });
zeroDaySchema.set('toJSON', toJSONConfig);

const alertaSchema = new mongoose.Schema({ titulo: String, descripcion: String, criticidad: String, fecha: { type: Date, required: true }, url: String }, { timestamps: true });
alertaSchema.set('toJSON', toJSONConfig);

const fuenteSchema = new mongoose.Schema({
    nombre: { type: String, required: true },
    fecha: { type: Date, required: true },
    tipo: String,
    url: String,
    descripcion: String
}, { timestamps: true });
fuenteSchema.set('toJSON', toJSONConfig);

const mitigacionSchema = new mongoose.Schema({
    titulo: { type: String, required: true },
    fecha: { type: Date, required: true },
    categoria: String,
    prioridad: String,
    descripcion: String,
    url: String
}, { timestamps: true });
mitigacionSchema.set('toJSON', toJSONConfig);

const cveSchema = new mongoose.Schema({
    cveId: { type: String, required: true, uppercase: true, trim: true, unique: true },
    fecha: { type: Date, required: true },
    aplicativo: String,
    cvss: Number,
    estado: String,
    descripcion: String,
    url: String
}, { timestamps: true });
cveSchema.set('toJSON', toJSONConfig);

const riskSchema = new mongoose.Schema({
  title: { type: String, required: true },
  customers: [String],
  tags: [String],
  priority: { type: String, enum: ['low', 'medium', 'high'], default: 'medium' },
  description: String,
  status: { type: String, enum: ['detectado', 'notificado', 'mitigando', 'resuelto', 'riesgo-aceptado'], default: 'detectado' },
  createdAt: { type: Number, default: () => Date.now() },
  lastUpdated: { type: Number, default: () => Date.now() },
  activity: [{
    type: { type: String, enum: ['comment', 'status_change'] },
    timestamp: Number,
    text: String,
    status: String,
    comment: String
  }]
});
riskSchema.set('toJSON', toJSONConfig);

const rssFeedSchema = new mongoose.Schema({
    title: { type: String, required: true },
    url: { type: String, required: true }
}, { timestamps: true });
rssFeedSchema.set('toJSON', toJSONConfig);


// --- Modelos ---
const Incidente = mongoose.models.Incidente || mongoose.model('Incidente', incidenteSchema);
const Exploit = mongoose.models.Exploit || mongoose.model('Exploit', exploitSchema);
const ZeroDay = mongoose.models.ZeroDay || mongoose.model('ZeroDay', zeroDaySchema);
const Alerta = mongoose.models.Alerta || mongoose.model('Alerta', alertaSchema);
const Fuente = mongoose.models.Fuente || mongoose.model('Fuente', fuenteSchema);
const Mitigacion = mongoose.models.Mitigacion || mongoose.model('Mitigacion', mitigacionSchema);
const Cve = mongoose.models.Cve || mongoose.model('Cve', cveSchema);
const Risk = mongoose.models.Risk || mongoose.model('Risk', riskSchema);
const RssFeed = mongoose.models.RssFeed || mongoose.model('RssFeed', rssFeedSchema);


// =============================================================================
// SEEDING LOGIC (Inicializar Feeds si está vacío)
// =============================================================================
async function seedInitialFeeds() {
    try {
        const count = await RssFeed.countDocuments();
        if (count === 0) {
            console.log('🌱 Seeding initial RSS Feeds...');
            const initialFeeds = [
                { title: "Graham Cluley", url: "https://grahamcluley.com/feed/" },
                { title: "Schneier on Security", url: "https://www.schneier.com/tag/cybersecurity/feed/" },
                { title: "KrebsOnSecurity", url: "https://krebsonsecurity.com/feed/" },
                { title: "CSO Online", url: "https://www.csoonline.com/feed/" },
                { title: "Dark Reading", url: "https://www.darkreading.com/rss.xml" },
                { title: "We Live Security (ESET)", url: "https://www.welivesecurity.com/en/rss/feed/" },
                { title: "Sophos News", url: "https://news.sophos.com/en-us/feed/" },
                { title: "Cyberbuilders Substack", url: "https://cyberbuilders.substack.com/feed" },
                { title: "The Hacker News", url:"https://feeds.feedburner.com/TheHackersNews" },
                { title: "Zero Day Initiative", url:"https://www.zerodayinitiative.com/rss/published/"   },
                { title: "Daily dark web", url: "https://dailydarkweb.net/feed/"},
                { title: "Kev", url:"https://kevfeed.vercel.app/CISA-KEV.xml"},
                { title: "Trendmicro", url: "https://newsroom.trendmicro.com/news-releases?pagetemplate=rss"},
                { title: "Splunk", url: "https://advisory.splunk.com/feed.xml"},
                { title: "Incibe", url: "https://www.incibe.es/feed/vulnerabilities"},
                { title: "Splotius", url: "https://sploitus.com/rss"}
            ];
            await RssFeed.insertMany(initialFeeds);
            console.log('✅ Initial RSS Feeds seeded.');
        }
    } catch (error) {
        console.error('Error seeding feeds:', error);
    }
}

// =============================================================================
// RUTAS DE LA API (ENDPOINTS)
// =============================================================================

const apiRouter = express.Router();

const createCrudRoutesFor = (modelName, model) => {
    const router = express.Router();

    router.get('/', async (req, res) => { try { const sortKey = model.schema.path('fecha') ? { fecha: -1 } : { createdAt: -1 }; const items = await model.find().sort(sortKey); res.status(200).json(items); } catch (err) { res.status(500).json({ message: `Error al obtener datos para ${modelName}`, error: err.message }); } });
    router.post('/', async (req, res) => { try { const newItem = new model(req.body); const savedItem = await newItem.save(); res.status(201).json(savedItem); } catch (err) { console.error(`Error en POST /${modelName}:`, err); res.status(400).json({ message: `Error al crear el elemento en ${modelName}`, error: err.message, details: err.errors }); } });
    router.put('/:id', async (req, res) => { try { const updatedItem = await model.findByIdAndUpdate(req.params.id, req.body, { new: true, runValidators: true }); if (!updatedItem) return res.status(404).json({ message: "Elemento no encontrado para actualizar" }); res.status(200).json(updatedItem); } catch (err) { console.error(`Error en PUT /${modelName}/:id:`, err); res.status(400).json({ message: `Error al actualizar el elemento en ${modelName}`, error: err.message, details: err.errors }); } });
    router.delete('/:id', async (req, res) => { try { const deletedItem = await model.findByIdAndDelete(req.params.id); if (!deletedItem) return res.status(404).json({ message: "Elemento no encontrado para eliminar" }); res.status(204).send(); } catch (err) { res.status(500).json({ message: `Error al eliminar el elemento en ${modelName}`, error: err.message }); } });

    return router;
};

const cveRouter = express.Router();

cveRouter.get('/', async (req, res) => {
    try {
        const items = await Cve.find().sort({ fecha: -1 });
        res.status(200).json(items);
    } catch (err) {
        res.status(500).json({ message: 'Error al obtener datos para cves', error: err.message });
    }
});

cveRouter.post('/', async (req, res) => {
    try {
        const newItem = new Cve(req.body);
        const savedItem = await newItem.save();
        res.status(201).json(savedItem);
    } catch (err) {
        if (err.code === 11000) {
            return res.status(400).json({ message: `Error: El CVE ID '${req.body.cveId}' ya existe.`, error: err.message });
        }
        res.status(400).json({ message: 'Error al crear el elemento en cves', error: err.message, details: err.errors });
    }
});

cveRouter.put('/:id', async (req, res) => {
    try {
        const updateData = { ...req.body };
        delete updateData.cveId;

        const updatedItem = await Cve.findByIdAndUpdate(req.params.id, updateData, { new: true, runValidators: true });

        if (!updatedItem) {
            return res.status(404).json({ message: "CVE no encontrado para actualizar" });
        }
        res.status(200).json(updatedItem);
    } catch (err) {
        console.error(`Error en PUT /cves/:id:`, err);
        res.status(400).json({ message: 'Error al actualizar el CVE', error: err.message });
    }
});

cveRouter.delete('/:id', async (req, res) => {
    try {
        const deletedItem = await Cve.findByIdAndDelete(req.params.id);
        if (!deletedItem) return res.status(404).json({ message: "Elemento no encontrado para eliminar" });
        res.status(204).send();
    } catch (err) {
        res.status(500).json({ message: 'Error al eliminar el elemento en cves', error: err.message });
    }
});

// =============================================================================
// ENDPOINT ESPECIAL PARA DETALLES DE CVE
// =============================================================================
apiRouter.get('/cve-details/:cveId', async (req, res) => {
    const { cveId } = req.params;
    const nvdUrl = `https://services.nvd.nist.gov/rest/json/cves/2.0?cveId=${cveId}`;
    const circlUrl = `https://cve.circl.lu/api/cve/${cveId}`;

    try {
        console.log(`Intentando obtener ${cveId} desde la API de NVD...`);
        const nvdResponse = await axios.get(nvdUrl);

        if (nvdResponse.data && nvdResponse.data.vulnerabilities && nvdResponse.data.vulnerabilities.length > 0) {
            const vulnerability = nvdResponse.data.vulnerabilities[0].cve;
            let cvssScore = 0;
            let severity = 'N/A';

            if (vulnerability.metrics.cvssMetricV31) {
                cvssScore = vulnerability.metrics.cvssMetricV31[0].cvssData.baseScore;
                severity = vulnerability.metrics.cvssMetricV31[0].cvssData.baseSeverity;
            } else if (vulnerability.metrics.cvssMetricV30) {
                cvssScore = vulnerability.metrics.cvssMetricV30[0].cvssData.baseScore;
                severity = vulnerability.metrics.cvssMetricV30[0].cvssData.baseSeverity;
            }

            return res.status(200).json({
                cveId: vulnerability.id,
                cvss: cvssScore,
                severity: severity,
                description: (vulnerability.descriptions.find(d => d.lang === 'en') || {}).value || 'No description.'
            });
        }
        throw new Error("CVE not found in NVD, trying fallback.");

    } catch (nvdError) {
        try {
            const circlResponse = await axios.get(circlUrl);
            if (!circlResponse.data || Object.keys(circlResponse.data).length === 0) {
                return res.status(404).json({ message: `CVE ID ${cveId} no se encontró en ninguna fuente.` });
            }
            const cveData = circlResponse.data;
            const cvssScore = cveData.cvss || 0;
            let severity = 'N/A';
            if (cvssScore >= 9.0) severity = 'CRITICAL';
            else if (cvssScore >= 7.0) severity = 'HIGH';
            else if (cvssScore >= 4.0) severity = 'MEDIUM';
            else if (cvssScore > 0) severity = 'LOW';

            return res.status(200).json({
                cveId: cveData.id,
                cvss: cvssScore,
                severity: severity,
                description: cveData.summary || 'No description available.'
            });

        } catch (circlError) {
            return res.status(500).json({ message: 'Ambas APIs (NVD y CIRCL) fallaron al obtener los datos del CVE.' });
        }
    }
});

// --- Asignación de Rutas a la API ---
apiRouter.use('/incidentes', createCrudRoutesFor('incidentes', Incidente));
apiRouter.use('/exploits', createCrudRoutesFor('exploits', Exploit));
apiRouter.use('/zerodays', createCrudRoutesFor('zerodays', ZeroDay));
apiRouter.use('/alertas', createCrudRoutesFor('alertas', Alerta));
apiRouter.use('/fuentes', createCrudRoutesFor('fuentes', Fuente));
apiRouter.use('/mitigaciones', createCrudRoutesFor('mitigaciones', Mitigacion));
apiRouter.use('/riesgos', createCrudRoutesFor('riesgos', Risk));
apiRouter.use('/cves', cveRouter);
apiRouter.use('/rss-feeds', createCrudRoutesFor('rss-feeds', RssFeed));

// Montamos router principal de la API
app.use('/api', apiRouter);

// =============================================================================
// RUTA DE "CATCH-ALL" PARA EL FRONTEND (SPA fallback)
// Esta ruta debe ir DESPUÉS de todas las rutas de la API.
// =============================================================================
app.get('/*path', (req, res) => { // <--- CAMBIO AQUÍ: de '/*' a '/*path'
    res.sendFile(path.resolve(FE_DIST_PATH, 'index.html'), (err) => {
        if (err) {
            console.error('❌ Error al servir index.html para el enrutamiento del cliente:', err);
            res.status(500).send('No se pudo servir la aplicación frontend.');
        }
    });
});

// =============================================================================
// MANEJADOR GENÉRICO DE 404
// =============================================================================
app.use((req, res) => {
    res.status(404).json({ message: 'Recurso no encontrado. Verifique la URL y el método HTTP.' });
});

app.listen(PORT, () => {
    console.log(`✅ Backend y Frontend servidos desde http://localhost:${PORT}`);
    console.log(`ℹ️  Asegúrate de que tu frontend esté construido en '${path.relative(process.cwd(), FE_DIST_PATH)}' con respecto a donde ejecutas 'node server.js'.`);
});
// --- END OF FILE server.js ---


